package com.trademaster.ims.mobile.checkout.model;import jakarta.persistence.*;import java.time.Instant;
@Entity @Table(name="customer_order_status_history")public class CustomerOrderStatusHistory{@Id @GeneratedValue(strategy=GenerationType.IDENTITY)private Long id;@Column(name="order_id",nullable=false)private Long orderId;@Column(nullable=false,length=40)private String status;@Column(name="customer_note",length=500)private String customerNote;@Column(name="created_at",nullable=false)private Instant createdAt;@PrePersist void c(){if(createdAt==null)createdAt=Instant.now();}public Long getId(){return id;}public Long getOrderId(){return orderId;}public String getStatus(){return status;}public String getCustomerNote(){return customerNote;}public Instant getCreatedAt(){return createdAt;}public void setOrderId(Long v){orderId=v;}public void setStatus(String v){status=v;}public void setCustomerNote(String v){customerNote=v;}public void setCreatedAt(Instant v){createdAt=v;}}
